int calculateMinimumPathSumImpl(int grid[][205], int rowCount, int colCount) {
    int dp[205];

    dp[0] = grid[0][0];

    // First row
    for (int j = 1; j < colCount; j++) {
        dp[j] = dp[j - 1] + grid[0][j];
    }

    // Remaining rows
    for (int i = 1; i < rowCount; i++) {
        dp[0] += grid[i][0];
        for (int j = 1; j < colCount; j++) {
            int best = dp[j] < dp[j - 1] ? dp[j] : dp[j - 1];
            dp[j] = best + grid[i][j];
        }
    }

    return dp[colCount - 1];
}

