class Solution {
    public int calculateMinimumPathSum(int[][] grid) {
        int n = grid.length;
        int m = grid[0].length;  // guaranteed rectangular now

        int[] dp = new int[m];
        dp[0] = grid[0][0];

        // Fill first row
        for (int j = 1; j < m; j++) {
            dp[j] = dp[j - 1] + grid[0][j];
        }

        // Fill remaining rows
        for (int i = 1; i < n; i++) {
            dp[0] += grid[i][0];
            for (int j = 1; j < m; j++) {
                dp[j] = Math.min(dp[j], dp[j - 1]) + grid[i][j];
            }
        }

        return dp[m - 1];
    }
}

